import React from 'react';
import { Navbar, Nav, Container } from 'react-bootstrap';
import './Header.css';

const Header = () => {
  return (
    <Navbar bg="dark" variant="dark" expand="lg" className="justify-content-center">
      <Container>
        <Navbar.Toggle aria-controls="basic-navbar-nav" />
        <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="m-auto" variant="tab">
            <Nav.Link href="#home" eventKey="home" className="custom-tab">Home</Nav.Link>
            <Nav.Link href="#resume" eventKey="resume" className="custom-tab">Resume</Nav.Link>
            <Nav.Link href="#publications" eventKey="publications" className="custom-tab">Publications</Nav.Link>
            <Nav.Link href="#contact" eventKey="contact" className="custom-tab">Contact</Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  );
};

export default Header;
